import { toolbarOverlayPadding } from './SingleValueToolbar.sty.js';
import { IntentProps } from '../../../../../core/slots/Intent/Intent.js';
import { ChartOverlaysElevation } from '../../../constants.js';
import {
  InternalChartToolbarConfig,
  type ChartToolbarConfig,
  type ToolbarPlacement,
} from '../../../types/toolbar.js';
import { getA11yToolbarConfig } from '../../../utils/zoom.js';
import { ChartToolbarRenderer } from '../../toolbar/ChartToolbarRenderer.js';
import type { IntentsAsyncTemplate } from '../../toolbar/types.js';
import {
  MINIMUM_HEIGHT_FOR_TOOLBAR,
  MINIMUM_HEIGHT_FOR_TOOLBAR_WITH_PADDING,
} from '../constants.js';

/** Configuration properties for the ChartToolbar in SingleValue
 * @public
 */
export interface SingleValueToolbarConfig
  extends Omit<ChartToolbarConfig, 'downloadData'> {
  /** Decides the placement of the toolbar */
  placement: ToolbarPlacement;
  /** Decides if the toolbar is hidden */
  hidden: boolean;
}

interface SingleValueToolbarProps extends InternalChartToolbarConfig {
  /** Intents to show in the toolbar */
  intents?: Array<IntentProps>;
  /** Decides if the toolbar is hidden */
  hidden: boolean;
  parentHeight: number;
  intentsAsyncTemplate?: IntentsAsyncTemplate;
}

export const SingleValueToolbar = (props: SingleValueToolbarProps) => {
  const {
    parentHeight,
    hidden,
    intents,
    intentsAsyncTemplate,
    placement = 'top-right',
    draggable,
  } = props;

  const hasEnoughHeightForToolbar = parentHeight > MINIMUM_HEIGHT_FOR_TOOLBAR;
  const isToolbarEnabled =
    hasEnoughHeightForToolbar &&
    !hidden &&
    !!(intents?.length ?? intentsAsyncTemplate);

  if (!isToolbarEnabled) {
    return null;
  }

  const overlayClassName =
    parentHeight > MINIMUM_HEIGHT_FOR_TOOLBAR_WITH_PADDING
      ? undefined
      : toolbarOverlayPadding;

  return (
    <ChartToolbarRenderer
      visible={false}
      placement={placement}
      initialA11yState={getA11yToolbarConfig({
        intent: !!intents,
      })}
      menuDisplayMode="never"
      intents={intents}
      overlayClassName={overlayClassName}
      visibleWhenMouseInBounds
      intentsAsyncTemplate={intentsAsyncTemplate}
      zIndex={ChartOverlaysElevation.toolbar}
      draggable={draggable}
      removeDragHandle
    />
  );
};

SingleValueToolbar['displayName'] = 'SingleValueToolbar';
